132	        .order('created_at', { ascending: false })
133	        .limit(2),
134	    ]);
135	
136	    const topSimilar = ((similar as Array<{ content: string; similarity: number }>) || [])
137	      .filter(m => m.similarity > 0.68)
138	      .map(m => m.content.slice(0, 150));
139	
140	    // Merge recent facts deduped against similarity results
141	    const seen = new Set(topSimilar);
142	    const all = [...topSimilar];
143	    for (const m of ((recent as Array<{ content: string }>) || [])) {
144	      const c = m.content.slice(0, 100);
145	      if (!seen.has(c)) { seen.add(c); all.push(c); }
146	    }
147	
148	    return all.length > 0 ? `WHAT I REMEMBER ABOUT YOU:\n${all.map(c => `- ${c}`).join('\n')}` : '';
149	  } catch (e) {
150	    console.warn('[Kira] Memory fetch error:', e);
151	    return '';
152	  }
153	}
