                                    onKeyDown={(e) => {
                                      if (e.key === 'Enter' && !e.shiftKey) {
                                        e.preventDefault();
                                        handleEditRetry(idx);
                                      }
                                      if (e.key === 'Escape') setEditingMessageIdx(null);
                                    }}
                                  />
                                  <div className="flex gap-2 justify-end">
                                    <button
                                      onClick={() => { setEditingMessageIdx(null); setEditingContent(""); }}
