34	    noir: { bg: "bg-gradient-to-br from-zinc-900 to-neutral-950", text: "text-white", lightText: true },
35	    sapphire: { bg: "bg-gradient-to-br from-blue-700 to-indigo-900", text: "text-white", lightText: true },
36	    burgundy: { bg: "bg-gradient-to-br from-rose-900 to-red-950", text: "text-white", lightText: true },
37	    emerald: { bg: "bg-gradient-to-br from-emerald-700 to-green-900", text: "text-white", lightText: true },
38	    lavender: { bg: "bg-gradient-to-br from-violet-400 to-purple-500", text: "text-white", lightText: true },
39	    champagne: { bg: "bg-gradient-to-br from-amber-100 to-yellow-50", text: "text-gray-900", lightText: false },
40	    coral: { bg: "bg-gradient-to-br from-orange-400 to-rose-500", text: "text-white", lightText: true },
41	    arctic: { bg: "bg-gradient-to-br from-sky-100 to-blue-200", text: "text-slate-800", lightText: false },
42	    copper: { bg: "bg-gradient-to-br from-amber-600 to-orange-800", text: "text-white", lightText: true },
43	    obsidian: { bg: "bg-gradient-to-br from-gray-950 to-slate-900", text: "text-white", lightText: true },
44	    peach: { bg: "bg-gradient-to-br from-orange-100 to-pink-100", text: "text-gray-800", lightText: false },
45	    steel: { bg: "bg-gradient-to-br from-slate-400 to-slate-600", text: "text-white", lightText: true },
46	    aurora: { bg: "bg-gradient-to-br from-purple-900 via-teal-800 to-green-900", text: "text-white", lightText: true },
47	    crimson: { bg: "bg-gradient-to-br from-red-600 to-rose-800", text: "text-white", lightText: true },
