53	  const currentTheme = themeMap[theme] || themeMap.dark;
54	
55	  // Font family class
56	  const fontMap: Record<string, string> = {
57	    poppins: "font-poppins",
58	    vollkorn: "font-vollkorn",
59	    inter: "font-[Inter]",
60	    playfair: "font-[Playfair_Display]",
61	  };
62	  const fontClass = fontMap[fontFamily] || "font-poppins";
63	
64	  // Button border radius
65	  const btnRadiusMap: Record<string, string> = {
66	    rounded: "rounded-full",
67	    sharp: "rounded-none",
68	    soft: "rounded-lg",
69	    pill: "rounded-full",
70	  };
71	  const btnRadius = btnRadiusMap[buttonStyle] || "rounded-full";
72	
73	  // Button variant styles
74	  const getButtonClasses = (style?: string) => {
75	    const base = `w-full py-2.5 px-4 text-center text-xs font-medium transition-all shadow-sm ${btnRadius}`;
76	    switch (style) {
77	      case "outline":
78	        return cn(base, currentTheme.lightText 
79	          ? "bg-transparent border border-white/40 text-white" 
80	          : "bg-transparent border border-gray-400 text-gray-900");
81	      case "minimal":
82	        return cn(base, currentTheme.lightText
83	          ? "bg-white/10 text-white backdrop-blur-sm"
84	          : "bg-gray-100 text-gray-900");
85	      case "filled":
86	      default:
87	        return cn(base, "bg-white text-gray-900");
88	    }
89	  };
90	
91	  const visibleButtons = buttons.filter(b => b.visible !== false);
92	
93	  return (
94	    <div className="relative mx-auto w-[280px]">
95	      {/* Phone Frame */}
96	      <div className="relative rounded-[3rem] border-[12px] border-gray-800 bg-gray-800 shadow-2xl overflow-hidden">
