102	          {/* Scrollable content area */}
103	          <div 
104	            className={cn(
105	              "flex-1 overflow-y-auto relative scrollbar-none",
106	              !isCustomImage && currentTheme.bg,
107	              fontClass
108	            )}
109	            style={isCustomImage ? { 
