121	                backgroundImage: 'radial-gradient(circle, currentColor 1px, transparent 1px)',
122	                backgroundSize: '16px 16px'
123	              }} />
124	            )}
125	            
126	            {/* Blur overlay */}
127	            {bgStyle === "blur" && !isCustomImage && (
128	              <div className="absolute inset-0 backdrop-blur-sm bg-white/5 z-0" />
129	            )}
130	
131	            <div className={cn(
132	              "pt-10 pb-4 px-5 relative z-10",
133	              fadeAnimation && "animate-fade-in"
134	            )}>
135	              {/* Profile Section */}
136	              <div className="text-center mb-5">
137	                {linkProfile?.profile_picture ? (
138	                  <Avatar className="w-20 h-20 mx-auto mb-3 ring-2 ring-white/20">
139	                    <AvatarImage src={linkProfile.profile_picture} />
140	                    <AvatarFallback className="bg-gradient-to-br from-bronze/30 to-bronze-dark/30 text-2xl font-bold">
141	                      {linkProfile?.display_name?.[0]?.toUpperCase() || "U"}
142	                    </AvatarFallback>
143	                  </Avatar>
144	                ) : (
145	                  <div className={cn(
146	                    "w-20 h-20 mx-auto mb-3 rounded-full bg-gradient-to-br from-bronze/30 to-bronze-dark/30 flex items-center justify-center ring-2 ring-white/20",
147	                  )}>
148	                    <span className={cn("text-2xl font-bold", currentTheme.text)}>
149	                      {linkProfile?.display_name?.[0]?.toUpperCase() || "U"}
150	                    </span>
151	                  </div>
152	                )}
153	                
154	                <div className="flex items-center justify-center gap-1 mb-1">
155	                  <h2 className={cn("font-semibold text-lg", currentTheme.text)}>
156	                    {linkProfile?.display_name || "Your Name"}
