167	                {linkProfile?.bio && (
168	                  <p className={cn("text-[10px] opacity-80 max-w-[200px] mx-auto leading-relaxed", currentTheme.text)}>
169	                    {linkProfile.bio}
170	                  </p>
171	                )}
172	              </div>
173	
174	              {/* Buttons */}
175	              <div style={{ display: 'flex', flexDirection: 'column', gap: `${Math.max(4, buttonSpacing * 0.6)}px` }}>
176	                {visibleButtons.length > 0 ? (
177	                  visibleButtons.map((button, index) => (
178	                    <div
179	                      key={button.id}
