189	                        <div className="text-[9px] opacity-70 truncate mt-0.5">{button.subtitle}</div>
190	                      )}
191	                    </div>
192	                  ))
193	                ) : (
194	                  <>
195	                    <div className={getButtonClasses("filled")}>My Portfolio</div>
196	                    <div className={getButtonClasses("filled")}>Book Me</div>
197	                    <div className={getButtonClasses("filled")}>Latest Work</div>
198	                  </>
199	                )}
200	              </div>
201	            </div>
202	          </div>
203	
204	        </div>
205	      </div>
206	    </div>
207	  );
208	};
209	
