  };
  const fontClass = fontMap[fontFamily] || "font-poppins";

  // Button border radius
  const btnRadiusMap: Record<string, string> = {
    rounded: "rounded-full",
    sharp: "rounded-none",
    soft: "rounded-lg",
    pill: "rounded-full",
  };
  const btnRadius = btnRadiusMap[buttonStyle] || "rounded-full";

