            <div className={cn(
              "pt-10 pb-4 px-5 relative z-10",
              fadeAnimation && "animate-fade-in"
            )}>
              {/* Profile Section */}
              <div className="text-center mb-5">
                {linkProfile?.profile_picture ? (
