                  </Avatar>
                ) : (
                  <div className={cn(
                    "w-20 h-20 mx-auto mb-3 rounded-full bg-gradient-to-br from-bronze/30 to-bronze-dark/30 flex items-center justify-center ring-2 ring-white/20",
